import{_ as e,c as o,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Funcionalidades Principais: Três Capacidades Essenciais | opencode-dcp","description":"Aprenda as três funcionalidades principais do opencode-dcp: estratégias de poda automática, ferramentas orientadas por LLM e comandos Slash. Domine essas funcionalidades para aproveitar ao máximo o potencial de otimização de tokens.","frontmatter":{"title":"Funcionalidades Principais: Três Capacidades Essenciais | opencode-dcp","sidebarTitle":"Desbloqueie as Três Capacidades","subtitle":"Funcionalidades Principais: Três Capacidades Essenciais","description":"Aprenda as três funcionalidades principais do opencode-dcp: estratégias de poda automática, ferramentas orientadas por LLM e comandos Slash. Domine essas funcionalidades para aproveitar ao máximo o potencial de otimização de tokens.","order":20},"headers":[],"relativePath":"pt/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md","filePath":"pt/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"}'),i={name:"pt/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"};function d(n,a,r,c,p,l){return s(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="funcionalidades-principais" tabindex="-1">Funcionalidades Principais <a class="header-anchor" href="#funcionalidades-principais" aria-label="Permalink to &quot;Funcionalidades Principais&quot;">​</a></h1><p>Este capítulo explora em profundidade as três capacidades essenciais do DCP: estratégias de poda automática, ferramentas orientadas por LLM e comandos Slash. Ao dominar essas funcionalidades, você poderá aproveitar ao máximo o potencial de otimização de tokens do DCP.</p><h2 id="conteudo-deste-capitulo" tabindex="-1">Conteúdo deste Capítulo <a class="header-anchor" href="#conteudo-deste-capitulo" aria-label="Permalink to &quot;Conteúdo deste Capítulo&quot;">​</a></h2><div class="grid-cards"><h3 id="estrategias-de-poda-automatica" tabindex="-1"><a href="./auto-pruning/">Estratégias de Poda Automática</a> <a class="header-anchor" href="#estrategias-de-poda-automatica" aria-label="Permalink to &quot;[Estratégias de Poda Automática](./auto-pruning/)&quot;">​</a></h3><p>Compreenda em detalhes como funcionam as três estratégias automáticas do DCP: estratégia de deduplicação, estratégia de sobrescrita e estratégia de limpeza de erros. Entenda as condições de ativação e os cenários de aplicação de cada estratégia.</p><h3 id="ferramentas-de-poda-orientadas-por-llm" tabindex="-1"><a href="./llm-tools/">Ferramentas de Poda Orientadas por LLM</a> <a class="header-anchor" href="#ferramentas-de-poda-orientadas-por-llm" aria-label="Permalink to &quot;[Ferramentas de Poda Orientadas por LLM](./llm-tools/)&quot;">​</a></h3><p>Entenda como a IA invoca autonomamente as ferramentas <code>discard</code> e <code>extract</code> para otimizar o contexto. Esta é a funcionalidade mais inteligente do DCP, permitindo que a IA participe ativamente do gerenciamento de contexto.</p><h3 id="uso-dos-comandos-slash" tabindex="-1"><a href="./commands/">Uso dos Comandos Slash</a> <a class="header-anchor" href="#uso-dos-comandos-slash" aria-label="Permalink to &quot;[Uso dos Comandos Slash](./commands/)&quot;">​</a></h3><p>Domine o uso de todos os comandos do DCP: <code>/dcp context</code> para visualizar o estado do contexto, <code>/dcp stats</code> para ver estatísticas e <code>/dcp sweep</code> para acionar a poda manualmente.</p></div><h2 id="roteiro-de-aprendizado" tabindex="-1">Roteiro de Aprendizado <a class="header-anchor" href="#roteiro-de-aprendizado" aria-label="Permalink to &quot;Roteiro de Aprendizado&quot;">​</a></h2><p>Recomendamos seguir esta ordem para estudar o conteúdo deste capítulo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Estratégias de Poda Automática → Ferramentas Orientadas por LLM → Comandos Slash</span></span>
<span class="line"><span>            ↓                              ↓                           ↓</span></span>
<span class="line"><span>    Compreender os princípios      Dominar a poda inteligente    Aprender a monitorar e depurar</span></span></code></pre></div><ol><li><strong>Comece pelas estratégias de poda automática</strong>: Esta é a base do DCP — entenda como funcionam as três estratégias</li><li><strong>Em seguida, aprenda as ferramentas orientadas por LLM</strong>: Após compreender as estratégias automáticas, aprenda a capacidade mais avançada de poda proativa pela IA</li><li><strong>Por fim, aprenda os comandos Slash</strong>: Domine os métodos de monitoramento e controle manual para facilitar a depuração e otimização</li></ol><div class="tip custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Antes de estudar este capítulo, certifique-se de ter concluído:</p><ul><li><a href="./../start/getting-started/">Instalação e Início Rápido</a> - Instalação do plugin DCP concluída</li><li><a href="./../start/configuration/">Guia Completo de Configuração</a> - Compreensão dos conceitos básicos do sistema de configuração</li></ul></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode continuar explorando:</p><ul><li><strong><a href="./../advanced/protection/">Mecanismos de Proteção</a></strong> - Aprenda a proteger conteúdo crítico contra poda acidental</li><li><strong><a href="./../advanced/state-persistence/">Persistência de Estado</a></strong> - Entenda como o DCP mantém o estado entre sessões</li><li><strong><a href="./../advanced/prompt-caching/">Impacto no Cache de Prompts</a></strong> - Compreenda as compensações entre DCP e Prompt Caching</li></ul>`,12)])])}const h=e(i,[["render",d]]);export{u as __pageData,h as default};
